def _anaplan_module_to_nested(anaplan_module: AnaplanModule) -> AnaplanModuleNested:
    """Convert flat AnaplanModule to nested format."""
    attrs = AnaplanModuleAttributes()
    _populate_anaplan_module_attrs(attrs, anaplan_module)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        anaplan_module, _ANAPLAN_MODULE_REL_FIELDS, AnaplanModuleRelationshipAttributes
    )
    return AnaplanModuleNested(
        guid=anaplan_module.guid,
        type_name=anaplan_module.type_name,
        status=anaplan_module.status,
        version=anaplan_module.version,
        create_time=anaplan_module.create_time,
        update_time=anaplan_module.update_time,
        created_by=anaplan_module.created_by,
        updated_by=anaplan_module.updated_by,
        classifications=anaplan_module.classifications,
        classification_names=anaplan_module.classification_names,
        meanings=anaplan_module.meanings,
        labels=anaplan_module.labels,
        business_attributes=anaplan_module.business_attributes,
        custom_attributes=anaplan_module.custom_attributes,
        pending_tasks=anaplan_module.pending_tasks,
        proxy=anaplan_module.proxy,
        is_incomplete=anaplan_module.is_incomplete,
        provenance_type=anaplan_module.provenance_type,
        home_id=anaplan_module.home_id,
        depth=anaplan_module.depth,
        immediate_upstream=anaplan_module.immediate_upstream,
        immediate_downstream=anaplan_module.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _anaplan_module_from_nested(nested: AnaplanModuleNested) -> AnaplanModule:
    """Convert nested format to flat AnaplanModule."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else AnaplanModuleAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _ANAPLAN_MODULE_REL_FIELDS,
        AnaplanModuleRelationshipAttributes,
    )
    return AnaplanModule(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_anaplan_module_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _anaplan_module_to_nested_bytes(
    anaplan_module: AnaplanModule, serde: Serde
) -> bytes:
    """Convert flat AnaplanModule to nested JSON bytes."""
    return serde.encode(_anaplan_module_to_nested(anaplan_module))


def _anaplan_module_from_nested_bytes(data: bytes, serde: Serde) -> AnaplanModule:
    """Convert nested JSON bytes to flat AnaplanModule."""
    nested = serde.decode(data, AnaplanModuleNested)
    return _anaplan_module_from_nested(nested)


